class Media:
    def __init__(self, media=None, css=None, js=None):
        if media is not None:
            css = media.css if hasattr(media, 'css') else {}
            js = media.js if hasattr(media, 'js') else []
        else:
            if css is None:
                css = {}
            if js is None:
                js = []
        self._css_lists = [css]
        self._js_lists = [js]

    def __repr__(self):
        return 'Media(css={}, js={})'.format(self._css, self._js)

    def __str__(self):
        return self.render()

    @property
    def _css(self):
        css = self._css_lists[0]
        for obj in self._css_lists[1:]:
            css = {medium: self.merge(css.get(medium, []), obj.get(medium, [])) for medium in css.keys() | obj.keys()}
        return css

    @property
    def _js(self):
        js = self._js_lists[0]
        for obj in self._js_lists[1:]:
            js = self.merge(js, obj)
        return js

    def render(self):
        return mark_safe('\n'.join(chain.from_iterable(getattr(self, 'render_' + name)() for name in MEDIA_TYPES)))

    def render_js(self):
        return [format_html('<script type="text/javascript" src="{}"></script>', self.absolute_path(path)) for path in self._js]

