        media = sorted(self._css)
        return chain.from_iterable([format_html('<link href="{}" type="text/css" media="{}" rel="stylesheet">', self.absolute_path(path), medium) for path in self._css[medium]] for medium in media)

    def absolute_path(self, path):
        if path.startswith(('http://', 'https://', '/')):
            return path
        return static(path)

    def __getitem__(self, name):
        if name in MEDIA_TYPES:
            return Media(**{str(name): getattr(self, '_' + name)})
        raise KeyError('Unknown media type "{}"'.format(name))

    @staticmethod
    def merge(list_1, list_2):
        combined_list = list(list_1)
        last_insert_index = len(list_1)
        for path in reversed(list_2):
            try:
                index = combined_list.index(path)
            except ValueError:
                combined_list.insert(last_insert_index, path)
            else:
                if index > last_insert_index:
                    warnings.warn('Detected duplicate Media files in an opposite order:\n{}{}\n{}'.format(combined_list[last_insert_index], combined_list[index], combined_list[index]), MediaOrderConflictWarning)
                last_insert_index = index
        return combined_list

    def __add__(self, other):
        combined = Media()
        combined._css_lists = self._css_lists + other._css_lists
        combined._js_lists = self._js_lists + other._js_lists
        return combined

