from django.apps import apps
from django.core.management.base import BaseCommand, CommandError
from django.db import DEFAULT_DB_ALIAS, connections
from django.db.migrations.executor import MigrationExecutor
from django.db.migrations.loader import AmbiguityError

class Command(BaseCommand):
    help = "Prints the SQL statements for the named migration."
    output_transaction = True

    def add_arguments(self, parser):
        parser.add_argument('app_label', help='App label of the application containing the migration.')
        parser.add_argument('migration_name', help='Migration name to print the SQL for.')
        parser.add_argument(
            '--database', default=DEFAULT_DB_ALIAS, help='Nominates a database to create SQL for. Defaults to the "default" database.'
        )
        parser.add_argument(
            '--backwards', action='store_true', help='Creates SQL to unapply the migration, rather than to apply it'
        )

    def execute(self, *args, **options):
        options['no_color'] = True
        return super().execute(*args, **options)

    def handle(self, *args, **options):
        app_label, migration_name = options['app_label'], options['migration_name']
        try:
            app_config = apps.get_app_config(app_label)
        except LookupError as err:
            raise CommandError(str(err))
        if app_label not in [app_config.label for app_config in apps.get_app_configs() if app_config.label]:
            raise CommandError("App '%s' does not have migrations" % app_label)
        try:
            migration = MigrationExecutor(connections[options['database']]).loader.get_migration_by_prefix(app_label, migration_name)
        except AmbiguityError:
            raise CommandError("More than one migration matches '%s' in app '%s'. Please be more specific." % (migration_name, app_label))
        except KeyError:
            raise CommandError("Cannot find a migration matching '%s' from app '%s'. Is it in INSTALLED_APPS?" % (migration_name, app_label))
        targets = [(app_label, migration.name)]

        self.output_transaction = migration.atomic

        plan = [(MigrationExecutor(connections[options['database']]).loader.graph.nodes[targets[0]], options['backwards'])]
        sql_statements = MigrationExecutor(connections[options['database']]).collect_sql(plan)
        return '\n'.join(sql_statements)
