import re
from django.core import validators
from django.utils.deconstruct import deconstructible
from django.utils.translation import gettext_lazy as _

@deconstructible
class UsernameValidator:
    def __init__(self, allow_ascii=True):
        self.allow_ascii = allow_ascii

    @property
    def regex(self):
        if self.allow_ascii:
            return r'^[\w.@+-]+$'
        return r'^[\w.-_]+[a-zA-Z0-9_]+[a-zA-Z0-9_]*$'

    @property
    def message(self):
        if self.allow_ascii:
            return _('Enter a valid username. This value may contain only English letters, numbers, and @/./+/-/_ characters.')
        return _('Enter a valid username. This value may contain only letters, numbers, and @/./+/-/_ characters.')

    @property
    def flags(self):
        if self.allow_ascii:
            return re.ASCII
        return 0
