    def serialize(self):
        func_string, _ = serializer_factory(self.value.func).serialize()
        args_string, _ = serializer_factory(self.value.args).serialize()
        keywords_string, _ = serializer_factory(self.value.keywords).serialize()
        imports = {'import functools', *func_string, *args_string, *keywords_string}
        return 'functools.%s(%s, *%s, **%s)' % (self.value.__class__.__name__, func_string, args_string, keywords_string), imports

