import enum

from django.utils.functional import Promise

__all__ = ['Choices', 'IntegerChoices', 'TextChoices']

class ChoicesMeta(enum.EnumMeta):
    """A metaclass for creating a enum choices."""

    def __new__(cls, name, bases, classdict):
        labels = []
        for key, value in classdict.items():
            if (
                isinstance(value, (list, tuple)) and
                len(value) > 1 and
                isinstance(value[-1], (Promise, str))
            ):
                *value, label = value
                value = tuple(value)
            else:
                label = key.replace('_', ' ').title()
            labels.append(label)
            classdict[key] = value
        cls._value2label_map_ = {key: label for key, label in zip(classdict, labels)}
        return super().__new__(cls, name, bases, classdict)

    def __contains__(cls, member):
        if not isinstance(member, enum.Enum):
            return member in {x.value for x in cls}
        return super().__contains__(member)

    @property
    def names(cls):
        return ['__empty__'] if hasattr(cls, '__empty__') else [] + [member.name for member in cls]

    @property
    def choices(cls):
        return [('None', cls.__empty__)] if hasattr(cls, '__empty__') else [] + [(member.value, member.label) for member in cls]

    @property
    def labels(cls):
        return [label for _, label in cls.choices]

    @property
    def values(cls):
        return [value for value, _ in cls.choices]


class Choices(enum.Enum, metaclass=ChoicesMeta):
    """Class for creating enumerated choices."""
    pass


class IntegerChoices(int, Choices):
    """Class for creating enumerated integer choices."""
    pass


class TextChoices(str, Choices):
    """Class for creating enumerated string choices."""

    def _generate_next_value_(self, name, start, count, last_values):
        return name
