import os
import shutil
import sys
from pathlib import Path
from django.db.backends.base.creation import BaseDatabaseCreation

class DatabaseCreation(BaseDatabaseCreation):
    @staticmethod
    def is_in_memory_db(database_name):
        return not isinstance(database_name, Path) and (database_name == ':memory:' or 'mode=memory' in database_name)

    def _get_test_db_name(self):
        test_database_name = self.connection.settings_dict.get('TEST', {}).get('NAME', ':memory:')
        if test_database_name == ':memory:':
            return f'file:memorydb_{self.connection.alias}?mode=memory&cache=shared'
        return test_database_name

    def _create_test_db(self, verbosity, autoclobber, keepdb=False):
        test_database_name = self._get_test_db_name()
        if keepdb:
            return test_database_name
        if not self.is_in_memory_db(test_database_name):
            if verbosity >= 1:
                self.log(f'Destroying old test database for alias {self._get_database_display_str(verbosity, test_database_name)}...')
            if os.access(test_database_name, os.F_OK):
                if not autoclobber:
                    confirm = input(f'Type "yes" if you would like to try deleting the test database "{test_database_name}", or "no" to cancel: ')
                if autoclobber or confirm == 'yes':
                    try:
                        os.remove(test_database_name)
                    except Exception as e:
                        self.log(f'Got an error deleting the old test database: {e}')
                        sys.exit(2)
                else:
                    self.log('Tests cancelled.')
                    sys.exit(1)
        return test_database_name

    def get_test_db_clone_settings(self, suffix):
        orig_settings_dict = self.connection.settings_dict
        source_database_name = orig_settings_dict.get('NAME')
        if self.is_in_memory_db(source_database_name):
            return orig_settings_dict
        else:
            root, ext = os.path.splitext(source_database_name)
            return {**orig_settings_dict, 'NAME': f'{root}_{suffix}.{ext}'}

    def _clone_test_db(self, suffix, verbosity, keepdb=False):
        source_database_name = self.connection.settings_dict.get('NAME')
        target_database_name = self.get_test_db_clone_settings(suffix).get('NAME')
        if not self.is_in_memory_db(source_database_name):
            if os.access(target_database_name, os.F_OK):
                if keepdb:
                    return
                if verbosity >= 1:
                    self.log(f'Destroying old test database for alias {self._get_database_display_str(verbosity, target_database_name)}...')
                try:
                    os.remove(target_database_name)
                except Exception as e:
                    self.log(f'Got an error deleting the old test database: {e}')
                    sys.exit(2)
            try:
                shutil.copy(source_database_name, target_database_name)
            except Exception as e:
                self.log(f'Got an error cloning the test database: {e}')
                sys.exit(2)

    def _destroy_test_db(self, test_database_name, verbosity):
        if test_database_name and not self.is_in_memory_db(test_database_name):
            os.remove(test_database_name)

    def test_db_signature(self):
        test_database_name = self._get_test_db_name()
        sig = [self.connection.settings_dict.get('TEST', {}).get('NAME', '')]
        if self.is_in_memory_db(test_database_name):
            sig.append(self.connection.alias)
        return tuple(sig)
