            model = objs.model
        else:
            return False
        if self._has_signal_listeners(model):
            return False
        opts = model._meta
        return all(link == from_field for link in opts.concrete_model._meta.parents.values()) and all(related.field.remote_field.on_delete is DO_NOTHING for related in get_candidate_relations_to_delete(opts)) and not any(hasattr(field, 'bulk_related_objects') for field in opts.private_fields)

    def get_del_batches(self, objs, fields):
        field_names = [field.name for field in fields]
        conn_batch_size = max(connections[self.using].ops.bulk_batch_size(field_names, objs), 1)
        if len(objs) > conn_batch_size:
            return [objs[i:i + conn_batch_size] for i in range(0, len(objs), conn_batch_size)]
        else:
            return [objs]

    def collect(self, objs, source=None, nullable=False, collect_related=True, source_attr=None, reverse_dependency=False, keep_parents=False, fail_on_restricted=True):
        if self.can_fast_delete(objs):
            self.fast_deletes.append(objs)
            return
        new_objs = self.add(objs, source, nullable, reverse_dependency=reverse_dependency)
        if not new_objs:
            return
        model = new_objs[0].__class__
        if not keep_parents:
            concrete_model = model._meta.concrete_model
            for ptr in concrete_model._meta.parents.values():
                if ptr:
                    parent_objs = [getattr(obj, ptr.name) for obj in new_objs]
                    self.collect(parent_objs, source=model, source_attr=ptr.remote_field.related_name, collect_related=False, reverse_dependency=True, fail_on_restricted=False)
        if not collect_related:
            return
        if keep_parents:
            parents = set(model._meta.get_parent_list())
        model_fast_deletes = defaultdict(list)
        protected_objects = defaultdict(list)
        for related in get_candidate_relations_to_delete(model._meta):
            if keep_parents and related.model in parents:
                continue
            field = related.field
            if field.remote_field.on_delete == DO_NOTHING:
                continue
            related_model = related.related_model
            if self.can_fast_delete(related_model, from_field=field):
                model_fast_deletes[related_model].append(field)
                continue
            batches = self.get_del_batches(new_objs, [field])
            for batch in batches:
                sub_objs = self.related_objects(related_model, [field], batch)
                non_referenced_fields = [field for field in fields if field not in [f for f in related_model._meta.get_fields(include_hidden=True) if f.auto_created and not f.concrete and (f.one_to_one or f.one_to_many)]]
                if non_referenced_fields:
                    skip_field_deferring = True
                else:
                    skip_field_deferring = False
                # Non-referenced fields can be deferred if no signal receivers are connected for the related model as they'll never be exposed to the user. Skip field deferring when some relationships are select_related as interactions between both features are hard
                for field in non_referenced_fields:
                    if skip_field_deferring:
                        continue
                    # Recursively collect concrete model's parent models, but not their related objects. These will be found by meta.get_fields()
                    concrete_model = field.related_model._meta.concrete_model
                    for ptr in concrete_model._meta.parents.values():
                        if ptr:
                            parent_objs = [getattr(obj, ptr.name) for obj in sub_objs]
                            self.collect(parent_objs, source=field.related_model, source_attr=ptr.remote_field.related_name, collect_related=False, reverse_dependency=True, fail_on_restricted=False)
        return
