import collections
import re
from functools import partial
from itertools import chain

from django.core.exceptions import EmptyResultSet, FieldError
from django.db import DatabaseError, NotSupportedError
from django.db.models.constants import LOOKUP_SEP
from django.db.models.expressions import F, OrderBy, Random, RawSQL, Ref, Value
from django.db.models.functions import Cast
from django.db.models.query_utils import Q, select_related_descend
from django.db.models.sql.constants import (
    CURSOR, GET_ITERATOR_CHUNK_SIZE, MULTI, NO_RESULTS, ORDER_DIR, SINGLE,
)
from django.db.models.sql.query import Query, get_order_dir
from django.db.transaction import TransactionManagementError
from django.utils.functional import cached_property
from django.utils.hashable import make_hashable
from django.utils.regex_helper import _lazy_re_compile

class SQLCompiler:
    ordering_parts = _lazy_re_compile(r'^(.*)\s(?:ASC|DESC).*', re.MULTILINE | re.DOTALL)

    def __init__(self, query, connection, using):
        self.query = query
        self.connection = connection
        self.using = using
        self.quote_cache = {'*': '*'}
        self._meta_ordering = None

    def setup_query(self):
        if all(self.query.alias_refcount[a] == 0 for a in self.query.alias_map):
            self.query.get_initial_alias()
        self.select, self.klass_info, self.annotation_col_map = self.get_select()
        self.col_count = len(self.select)

    def pre_sql_setup(self):
        self.setup_query()
        order_by = self.get_order_by()
        self.where, self.having = self.query.where.split_having()
        extra_select = self.get_extra_select(order_by, self.select)
        self.has_extra_select = bool(extra_select)
        group_by = self.get_group_by(self.select + extra_select, order_by)
        return extra_select, order_by, group_by

    def get_group_by(self, select, order_by):
        ref_sources = {expr.source for expr in select if isinstance(expr, Ref)}
        result = []
        seen = set()
        for expr in select:
            if expr in ref_sources:
                continue
            cols = expr.get_group_by_cols()
            for col in cols:
                result.append(col)
        for expr, (sql, params, is_ref) in order_by:
            if not is_ref:
                result.extend(expr.get_group_by_cols())
        having_group_by = self.having.get_group_by_cols() if self.having else ()
        for expr in having_group_by:
            result.append(expr)
        result = self.collapse_group_by(result, having_group_by)
        return [(sql, params) for sql, params in result]

    def collapse_group_by(self, expressions, having):
        if self.connection.features.allows_group_by_pk:
            pk = None
            for expr in expressions:
                if getattr(expr, 'target', None) == self.query.model._meta.pk:
                    pk = expr
                    break
            if pk:
                expressions = [pk] + [expr for expr in expressions if expr not in having]
        elif self.connection.features.allows_group_by_selected_pks:
            pks = {expr for expr in expressions if hasattr(expr, 'target') and expr.target.primary_key}
            aliases = {expr.alias for expr in pks}
            expressions = [expr for expr in expressions if expr in pks or expr.alias not in aliases]
        return expressions

    def get_select(self):
        select = []
        klass_info = None
        annotations = {}
        select_idx = 0
        for alias, (sql, params) in self.query.extra_select.items():
            annotations[alias] = select_idx
            select.append((RawSQL(sql, params), alias))
            select_idx += 1
        if self.query.default_cols:
            cols = self.get_default_columns()
        else:
            cols = self.query.select
        if cols:
            select_list = []
            for col in cols:
                select_list.append(select_idx)
                select.append((col, None))
                select_idx += 1
            klass_info = {
                'model': self.query.model,
                'select_fields': select_list,
            }
        for alias, annotation in self.query.annotation_select.items():
            annotations[alias] = select_idx
            select.append((annotation, alias))
            select_idx += 1
        if self.query.select_related:
            related_klass_infos = self.get_related_selections(select)
            klass_info['related_klass_infos'] = related_klass_infos
            def get_select_from_parent(klass_info):
                for ki in klass_info['related_klass_infos']:
                    if ki['from_parent']:
                        ki['select_fields'] = (klass_info['select_fields'] + ki['select_fields'])
                    get_select_from_parent(ki)
            get_select_from_parent(klass_info)
        return select, klass_info, annotations

    def get_extra_select(self, order_by, select):
        return [expr for expr in select if expr not in order_by]

    def get_group_by_sql(self, select, order_by):
        result = []
        seen = set()
        for expr in select:
            sql, params = self.compile(expr)
            if (sql, params) in seen:
                continue
            result.append((sql, params))
            seen.add((sql, params))
        return result

    def get_order_by(self):
        return [(expr, (sql, params, is_ref)) for expr, (sql, params, is_ref) in self.query.order_by]
