class Query(BaseExpression):
    alias_prefix = 'T'
    subq_aliases = frozenset([alias_prefix])

    def __init__(self, model, where=WhereNode, alias_cols=True):
        self.model = model
        self.alias_refcount = {}
        self.alias_map = {}
