from django.core.management.base import BaseCommand, CommandError, CommandParser, handle_default_options
from django.core.management.color import color_style
from django.utils import autoreload

class CommandParser:
    def __init__(self, prog_name):
        self.prog_name = prog_name
        self.parser = CommandParser()

    def get_commands(self):
        return {name: 'django.core' for name in find_commands(__path__[0])}

    def load_command_class(self, app_name, name):
        module = import_module('%s.management.commands.%s' % (app_name, name))
        return module.Command()

    def call_command(self, command_name, *args, **options):
        if isinstance(command_name, BaseCommand):
            command = command_name
            command_name = command.__class__.__module__.split('.')[-1]
        else:
            try:
                app_name = self.get_commands()[command_name]
            except KeyError:
                raise CommandError("Unknown command: %r" % command_name)
            command = self.load_command_class(app_name, command_name)
        # Simulate argument parsing to get the option defaults (see #10080 for details).
        parser = command.create_parser('', command_name)
        # Use the `dest` option name from the parser option
        opt_mapping = {opt.dest: s_opt.dest for s_opt in parser._actions if s_opt.option_strings}
        arg_options = {opt_mapping.get(key, key): value for key, value in options.items()}
        parse_args = []
        for arg in args:
            if isinstance(arg, (list, tuple)):
                parse_args += map(str, arg)
            else:
                parse_args.append(str(arg))

        def get_actions(parser):
            # Parser actions and actions from sub-parser choices.
            for opt in parser._actions:
                if isinstance(opt, _SubParsersAction):
                    for sub_opt in opt.choices.values():
                        yield from get_actions(sub_opt)
                else:
                    yield opt

        parser_actions = list(get_actions(parser))
        mutually_exclusive_required_options = {opt for group in parser._mutually_exclusive_groups for opt in group._group_actions if group.required}
        # Any required arguments which are passed in via **options must be passed
        # to parse_args().
        for opt in parser_actions:
            if (opt.dest in options and (opt.required or opt in mutually_exclusive_required_options)):
                parse_args.append(min(opt.option_strings))
                if isinstance(opt, (_AppendConstAction, _CountAction, _StoreConstAction)):
                    continue
                value = arg_options[opt.dest]
                if isinstance(value, (list, tuple)):
                    parse_args += map(str, value)
                else:
                    parse_args.append(str(value))
        defaults = parser.parse_args(args=parse_args)
        defaults = dict(defaults._get_kwargs(), **arg_options)
        # Raise an error if any unknown options were passed.
        stealth_options = set(command.base_stealth_options + command.stealth_options)
        dest_parameters = {action.dest for action in parser_actions}
        valid_options = (dest_parameters | stealth_options).union(opt_mapping)
        unknown_options = set(options) - valid_options
        if unknown_options:
            raise TypeError(
                "Unknown option(s) for %s command: %s. "
                "Valid options are: %s." % (
                    command_name,
                    ', '.join(sorted(unknown_options)),
                    ', '.join(sorted(valid_options)),
                )
            )
        # Move positional args out of options to mimic legacy optparse
        args = defaults.pop('args', ())
        if 'skip_checks' not in options:
            defaults['skip_checks'] = True

        return command.execute(*args, **defaults)

class ManagementUtility:
    def __init__(self, argv=None):
        self.argv = argv or sys.argv[:]
