import getpass
import unicodedata

from django.apps import apps as global_apps
from django.contrib.auth import get_permission_codename
from django.contrib.contenttypes.management import create_contenttypes
from django.core import exceptions
from django.db import DEFAULT_DB_ALIAS, router

def _get_all_permissions(opts):
    return [*_get_builtin_permissions(opts), *opts.permissions]


def _get_builtin_permissions(opts):
    perms = []
    for action in opts.default_permissions:
        perms.append(
            (
                get_permission_codename(action, opts),
                f"Can {action} {opts.verbose_name_raw}",
            )
        )
    return perms


def create_permissions(
    app_config,
    verbosity=2,
    interactive=True,
    using=DEFAULT_DB_ALIAS,
    apps=global_apps,
    **kwargs,
):
    if not app_config.models_module:
        return

    create_contenttypes(
        app_config,
        verbosity=verbosity,
        interactive=interactive,
        using=using,
        apps=apps,
        **kwargs,
    )

    app_label = app_config.label
    try:
        app_config = apps.get_app_config(app_label)
        ContentType = apps.get_model("contenttypes", "ContentType")
        Permission = apps.get_model("auth", "Permission")
    except LookupError:
        return

    if not router.allow_migrate_model(using, Permission):
        return

    searched_perms = []
    ctypes = set()
    for klass in app_config.get_models():
        ctype = ContentType.objects.db_manager(using).get_for_model(
            klass, for_concrete_model=False
        )
        ctypes.add(ctype)
        for perm in _get_all_permissions(klass._meta):
            searched_perms.append((ctype, perm))

    all_perms = set(
        Permission.objects.using(using)
        .filter(content_type__in=ctypes)
        .values_list("content_type", "codename")
    )

    perms = [
        Permission(codename=codename, name=name, content_type=ct)
        for ct, (codename, name) in searched_perms
        if (ct.pk, codename) not in all_perms
    ]
    Permission.objects.using(using).bulk_create(perms)
    if verbosity >= 2:
        for perm in perms:
            print(f"Adding permission '{perm}'")


def get_system_username():
    try:
        return getpass.getuser()
    except (ImportError, KeyError):
        return ""


def get_default_username(check_db=True, database=DEFAULT_DB_ALIAS):
    from django.contrib.auth import models as auth_app

    default_username = get_system_username()
    try:
        default_username = unicodedata.normalize("NFKD", default_username).encode("ascii", "ignore").decode("ascii").replace(" ", "").lower()
    except UnicodeDecodeError:
        return ""

    if auth_app.User._meta.swapped:
        return ""

    # Run the username validator
    try:
        auth_app.User._meta.get_field("username").run_validators(default_username)
    except exceptions.ValidationError:
        return ""

    # Don't return the default username if it is already taken.
    if check_db and default_username:
        try:
            auth_app.User._default_manager.db_manager(database).get(username=default_username)
        except auth_app.User.DoesNotExist:
            pass
        else:
            return ""
    return default_username
