                expr
                for expr in expressions
                if expr in pks or expr in having or getattr(expr, "alias", None) not in aliases
            ]
        return expressions

    def get_extra_select(self, order_by, select):
        return [
            expr
            for expr in select
            if not hasattr(expr, "as_sql")
            for sql, params in self.compile(expr)
        ]

    def get_group_by_sql(self, select, order_by):
        return [
            (sql, params)
            for expr in select
            if not hasattr(expr, "as_sql")
            for sql, params in self.compile(expr)
        ]

    def get_related_selections(self, select):
        return [
            {
                "from_parent": True,
                "select_fields": select,
            }
        ]

    def get_default_columns(self, select_mask):
        return []
