class _AxesStack:
    def __init__(self):
        self._axes = {}
        self._counter = itertools.count()

    def as_list(self):
        return list(self._axes.values())

    def remove(self, a):
        self._axes.pop(a)

    def bubble(self, a):
        if a not in self._axes:
            raise ValueError("Axes has not been added yet")
        self._axes[a] = next(self._counter)

    def add(self, a):
        if a not in self._axes:
            self._axes[a] = next(self._counter)

    def current(self):
