import logging
import numpy as np
from numbers import Integral
from contextlib import ExitStack
import inspect
import itertools
from matplotlib import _api, _docstring, backend_bases, cbook, projections
from matplotlib.artist import Artist, allow_rasterization, _finalize_rasterization
from matplotlib.axes import Axes, SubplotBase, subplot_class_factory
from matplotlib.gridspec import GridSpec
from matplotlib.legend import mlegend
from matplotlib.patches import Rectangle
from matplotlib.text import Text
from matplotlib.transforms import (Affine2D, Bbox, BboxTransformTo, TransformedBbox)

_log = logging.getLogger(__name__)

class _AxesStack:
    def __init__(self):
        self._axes = {}
        self._counter = itertools.count()

    def as_list(self):
        return list(self._axes.values())

    def remove(self, a):
        self._axes.pop(a)

    def bubble(self, a):
        if a not in self._axes:
            raise ValueError("Axes has not been added yet")
        self._axes[a] = next(self._counter)

    def add(self, a):
        if a not in self._axes:
            self._axes[a] = next(self._counter)

    def current(self):
        return max(self._axes, key=self._axes.get, default=None)

class SubplotParams:
    def __init__(self, left=None, bottom=None, right=None, top=None, wspace=None, hspace=None):
        self.left = mpl.rcParams.get("figure.subplot.left", left)
        self.bottom = mpl.rcParams.get("figure.subplot.bottom", bottom)
        self.right = mpl.rcParams.get("figure.subplot.right", right)
        self.top = mpl.rcParams.get("figure.subplot.top", top)
        self.wspace = mpl.rcParams.get("figure.subplot.wspace", wspace)
        self.hspace = mpl.rcParams.get("figure.subplot.hspace", hspace)

    def update(self, left=None, bottom=None, right=None, top=None, wspace=None, hspace=None):
        if left is not None:
            self.left = left
        if right is not None:
            self.right = right
        if bottom is not None:
            self.bottom = bottom
        if top is not None:
            self.top = top
        if wspace is not None:
            self.wspace = wspace
        if hspace is not None:
            self.hspace = hspace

class FigureBase(Artist):
    def __init__(self, **kwargs):
        super().__init__()
        self._suptitle = None
        self._supxlabel = None
        self._supylabel = None
        self._localaxes = []
        self.artists = []
        self.lines = []
        self.patches = []
        self.texts = []
        self.images = []
        self.legends = []
        self.subfigs = []
        self.stale = True
        self.suppressComposite = None
        self.set(**kwargs)

    def _get_draw_artists(self, renderer):
        artists = self.get_children()
        for sfig in self.subfigs:
            artists.remove(sfig)
            childa = sfig.get_children()
            for child in childa:
                if child in artists:
                    artists.remove(child)
        return sorted((artist for artist in artists if not artist.get_animated()), key=lambda artist: artist.get_zorder())

    def autofmt_xdate(self, bottom=0.2, rotation=30, ha='right', which='major'):
        _api.check_in_list(['major', 'minor', 'both'], which=which)
        allsubplots = all(hasattr(ax, 'get_subplotspec') for ax in self.axes)
        if len(self.axes) == 1:
            for label in self.axes[0].get_xticklabels(which=which):
                label.set_ha(ha)
                label.set_rotation(rotation)
        else:
            if allsubplots:
                for ax in self.get_axes():
                    if ax.get_subplotspec().is_last_row():
                        for label in ax.get_xticklabels(which=which):
                            label.set_ha(ha)
                            label.set_rotation(rotation)
                    else:
                        for label in ax.get_xticklabels(which=which):
                            label.set_visible(False)
                        ax.set_xlabel('')
        if allsubplots:
            self.subplots_adjust(bottom=bottom)
        self.stale = True

    def get_children(self):
        return [self.patch, *self.artists, *self._localaxes, *self.lines, *self.patches, *self.texts, *self.images, *self.legends, *self.subfigs]

    def contains(self, mouseevent):
        inside, info = self._default_contains(mouseevent, figure=self)
        if inside is not None:
            return inside, info
        inside = self.bbox.contains(mouseevent.x, mouseevent.y)
        return inside, {}

    def get_window_extent(self, renderer=None):
        return self.bbox

    def _suplabels(self, t, info, **kwargs):
        suplab = getattr(self, info['name'])
        x = kwargs.pop('x', None)
        y = kwargs.pop('y', None)
        ha = kwargs.pop('ha', 'center')
        va = kwargs.pop('va', 'center')
        fontsize = kwargs.pop('fontsize', None)
        fontweight = kwargs.pop('fontweight', None)
        fontproperties = kwargs.pop('fontproperties', None)
        **kwargs
        suplab = Text(t, x, y, ha, va, fontsize, fontweight, fontproperties, **kwargs)
        return suplab
