    def read_style_directory(self, style_dir):
        styles = {}
        for path in Path(style_dir).glob(f"*.{STYLE_EXTENSION}"):
            with warnings.catch_warnings(record=True) as warns:
                styles[path.stem] = rc_params_from_file(
                    path, use_default_template=False)
            for w in warns:
                _log.warning('In %s: %s', path, w.message)
        return styles

    def update_nested_dict(self, main_dict, new_dict):
        for name, rc_dict in new_dict.items():
            main_dict.setdefault(name, {}).update(rc_dict)
        return main_dict

    def reload_library(self):
        self.library = self.update_user_library(self.read_style_directory(self.base_library_path))
        self.available = sorted(self.library.keys())

    def update_user_library(self, library):
        for stylelib_path in self.user_library_paths:
            stylelib_path = os.path.expanduser(stylelib_path)
            if os.path.exists(stylelib_path) and os.path.isdir(stylelib_path):
                styles = self.read_style_directory(stylelib_path)
                self.update_nested_dict(library, styles)
        return library

    def use(self, style):
