                    "seaborn-dark",
                    "seaborn-darkgrid",
                    "seaborn-dark-palette",
                    "seaborn-deep",
                    "seaborn-muted",
                    "seaborn-notebook",
                    "seaborn-paper",
                    "seaborn-pastel",
                    "seaborn-poster",
                    "seaborn-talk",
                    "seaborn-ticks",
                    "seaborn-white",
                    "seaborn-whitegrid",
                ]:
