from matplotlib.patches import Rectangle
from matplotlib.text import Text
from matplotlib.transforms import Affine2D, Bbox, BboxTransformTo, TransformedBbox

_log = logging.getLogger(__name__)

class _AxesStack:
    def __init__(self):
        self._axes = {}
        self._counter = itertools.count()

    def as_list(self):
        return list(self._axes.values())

    def remove(self, a):
        self._axes.pop(a)

    def bubble(self, a):
        if a not in self._axes:
            raise ValueError("Axes has not been added yet")
        self._axes[a] = next(self._counter)

    def add(self, a):
        if a not in self._axes:
            self._axes[a] = next(self._counter)

    def current(self):
        return max(self._axes, key=self._axes.get, default=None)

class SubplotParams:
    def __init__(self, left=None, bottom=None, right=None, top=None, wspace=None, hspace=None):
        for key in ["left", "bottom", "right", "top", "wspace", "hspace"]:
            setattr(self, key, mpl.rcParams[f"figure.subplot.{key}"])
        self.update(left, bottom, right, top, wspace, hspace)

    def update(self, left=None, bottom=None, right=None, top=None, wspace=None, hspace=None):
        if ((left if left is not None else self.left) >= (right if right is not None else self.right)):
            raise ValueError('left cannot be >= right')
        if ((bottom if bottom is not None else self.bottom) >= (top if top is not None else self.top)):
            raise ValueError('bottom cannot be >= top')
        if left is not None:
            self.left = left
        if right is not None:
            self.right = right
        if bottom is not None:
            self.bottom = bottom
        if top is not None:
            self.top = top
        if wspace is not None:
            self.wspace = wspace
        if hspace is not None:
            self.hspace = hspace

class FigureBase(Artist):
