        _api.check_in_list(["column", "row"], direction=direction)
        self._direction = direction

        axes_class = kwargs.pop("axes_class", self._defaultAxesClass)
        if isinstance(axes_class, (list, tuple)):
            cls, kwargs = axes_class
            axes_class = functools.partial(cls, **kwargs)

        self._divider = SubplotDivider(fig, rect, **kwargs)
        rect = self._divider.get_position()

        axes_array = np.full((self._nrows, self._ncols), None, dtype=object)
        for i in range(self.ngrids):
            col, row = self._get_col_row(i)
            if kwargs.pop("share_all", False):
                sharex = sharey = axes_array[0, 0]
            else:
                sharex = axes_array[0, col] if kwargs.pop("share_x", True) else None
                sharey = axes_array[row, 0] if kwargs.pop("share_y", True) else None
            axes_array[row, col] = axes_class(fig, rect, sharex=sharex, sharey=sharey)
        self.axes_all = axes_array.ravel(order="C" if self._direction == "row" else "F").tolist()
        self.axes_column = axes_array.T.tolist()
        self.axes_row = axes_array.tolist()
        self.axes_llc = self.axes_column[0][-1]

